function defaultState() {
    return {
        deviceId: "mcu01",
        sensor: {
            temperature: 0,
            humidity: 0,
            light: 0
        },
        actuator: false,
        updatedAt: null,
        commandUpdatedAt: null
    };
}

let body = msg.payload;

if (typeof body === "string") {
    try {
        body = JSON.parse(body);
    } catch (err) {
        msg.statusCode = 400;
        msg.headers = { "Content-Type": "application/json" };
        msg.payload = JSON.stringify({ ok: false, error: "Invalid JSON" });
        return msg;
    }
}

let state = flow.get("deviceState") || defaultState();

state.deviceId = body.id || state.deviceId || "mcu01";
state.sensor = {
    temperature: Number(body.temperature ?? body.temp ?? state.sensor.temperature ?? 0),
    humidity: Number(body.humidity ?? state.sensor.humidity ?? 0),
    light: Number(body.light ?? body.lux ?? state.sensor.light ?? 0)
};
state.updatedAt = new Date().toISOString();

flow.set("deviceState", state);

/*
  This response is important:
  a real microcontroller could POST sensor data and receive
  the latest actuator command in the same HTTP response.
*/
msg.headers = { "Content-Type": "application/json" };
msg.payload = JSON.stringify({
    ok: true,
    received: state.sensor,
    command: {
        actuator: state.actuator
    }
});
return msg;

